// Check if token was found
const token = $input.first().json.access_token;
if (!token) {
  return [{
    json: {
      error: true,
      message: '❌ No Gmail token found. Please run `/email auth` first to connect your Gmail account.',
      chatId: $('Execute Workflow Trigger').first().json.chatId
    }
  }];
}
return [{ json: { access_token: token, userId: $('Execute Workflow Trigger').first().json.userId, chatId: $('Execute Workflow Trigger').first().json.chatId } }];

// Extract message IDs to fetch
const messages = $input.first().json.messages || [];
if (messages.length === 0) {
  return [{ json: { noMessages: true, messages: [] } }];
}
// Return first 20 to avoid rate limits; enough for style analysis
return messages.slice(0, 20).map(m => ({ json: { id: m.id } }));

// Extract plain-text body from each fetched email
function decodeBody(parts) {
  if (!parts) return '';
  for (const part of parts) {
    if (part.mimeType === 'text/plain' && part.body && part.body.data) {
      return Buffer.from(part.body.data, 'base64').toString('utf-8');
    }
    if (part.parts) {
      const inner = decodeBody(part.parts);
      if (inner) return inner;
    }
  }
  return '';
}

const email = $input.first().json;
let bodyText = '';
if (email.payload) {
  if (email.payload.parts) {
    bodyText = decodeBody(email.payload.parts);
  } else if (email.payload.body && email.payload.body.data) {
    bodyText = Buffer.from(email.payload.body.data, 'base64').toString('utf-8');
  }
}

// Clamp to 500 chars per email to keep Gemini prompt manageable
return [{ json: { body: bodyText.substring(0, 500).trim() } }];

// Aggregate all email bodies into a single prompt
const bodies = $input.all().map((item, i) => `--- Email ${i + 1} ---\n${item.json.body}`).join('\n\n');

return [{
  json: {
    aggregatedBodies: bodies,
    userId: $('Execute Workflow Trigger').first().json.userId,
    chatId: $('Execute Workflow Trigger').first().json.chatId
  }
}];

