// Parse Gemini response and extract the JSON style object
const response = $input.first().json;
let styleData = {};

try {
  const rawText = response.candidates[0].content.parts[0].text;
  // Strip any accidental markdown code fences
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  styleData = JSON.parse(cleaned);
} catch (e) {
  // fallback defaults
  styleData = {
    formality_score: 0.5,
    common_greetings: ['Hi', 'Hello'],
    common_signoffs: ['Thanks', 'Best'],
    avg_sentence_length: 'medium',
    tone: 'professional',
    writing_patterns: ['Unable to analyze — defaulting to neutral style']
  };
}

return [{
  json: {
    userId: $('Aggregate Emails').first().json.userId,
    chatId: $('Aggregate Emails').first().json.chatId,
    formality_score: styleData.formality_score,
    common_greetings: JSON.stringify(styleData.common_greetings || []),
    common_signoffs: JSON.stringify(styleData.common_signoffs || []),
    avg_sentence_length: styleData.avg_sentence_length || 'medium',
    tone: styleData.tone || 'professional',
    writing_patterns: JSON.stringify(styleData.writing_patterns || []),
    displayFormality: Math.round((styleData.formality_score || 0.5) * 100),
    displayTone: styleData.tone || 'professional',
    displayGreetings: (styleData.common_greetings || []).join(', '),
    displaySignoffs: (styleData.common_signoffs || []).join(', ')
  }
}];

